import path from 'path';
import os from 'os';
import fs from 'fs';
import Dirty from "../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js";

describe('dirty drain event via write stream drain handler', () => {
  it('emits drain event via the write stream drain handler path', (done) => {
    const tmpFile = path.join(os.tmpdir(), `dirty-test-${process.pid}.db`);
    const db = new Dirty(tmpFile);

    db.on('load', () => {
      // Override write to force backpressure (return false) while still calling the callback
      const ws = db._writeStream;
      const origWrite = ws.write.bind(ws);

      ws.write = function(data, cb) {
        origWrite(data, cb); // actually write (calls cb eventually)
        return false;        // but signal backpressure
      };

      db.on('drain', () => {
        fs.unlink(tmpFile, () => {});
        done();
      });

      db.set('key1', 'value1');
    });
  }, 10000);
});
